const inputItem = mergeDataItems[itemIndex]?.json || {};
const imageBinary = mergeDataItems[itemIndex]?.binary || null;

let qaResult = { 
  approved: true, 
  quality_score: 7, 
  has_banned_content: false,
  has_brand_violations: false,
  detected_brands: [],
  rejection_reasons: [], 
  recommendation: 'approve',
  suggested_prompt_for_regeneration: ''
};

try {
  const content = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  const cleanJson = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  qaResult = JSON.parse(cleanJson);
} catch (e) {
  qaResult = { 
    approved: true, 
    quality_score: 6, 
    has_banned_content: false,
    has_brand_violations: false,
    detected_brands: [],
    rejection_reasons: ['parse_error'], 
    recommendation: 'approve',
    suggested_prompt_for_regeneration: ''
  };
}

if (geminiResponse.candidates?.[0]?.finishReason === 'SAFETY') {
  qaResult = { 
    approved: false, 
    quality_score: 0, 
    has_banned_content: true,
    has_brand_violations: false,
    detected_brands: [],
    rejection_reasons: ['safety_blocked'], 
    recommendation: 'reject',
    suggested_prompt_for_regeneration: ''
  };
}

const needsRegeneration = !qaResult.approved && 
  qaResult.recommendation === 'regenerate' && 
  !qaResult.has_banned_content &&
  (inputItem.regeneration_attempts || 0) < 2;

return {
  json: {
