const inputItem = $('Merge All Items').first().json;
const inputBinary = $('Merge All Items').first().binary;
const aiResponse = $json.choices?.[0]?.message?.content || '{}';

const BANNED_BRANDS = [
  'john deere', 'fendt', 'case ih', 'massey ferguson', 'new holland',
  'claas', 'kubota', 'nike', 'adidas', 'apple', 'samsung', 'google',
  'microsoft', 'sony', 'nintendo', 'playstation', 'xbox', 'tesla',
  'bmw', 'mercedes', 'audi', 'ford', 'chevrolet', 'toyota', 'honda',
  'coca-cola', 'pepsi', 'mcdonald', 'kfc', 'burger king', 'starbucks'
];

let parsed;
try {
  const cleanJson = aiResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleanJson);
} catch (e) {
  parsed = {
    title: (inputItem.raw_title || 'Minecraft Mod').substring(0, 30),
    description: `This ${inputItem.section} adds new features to Minecraft.`,
    brand_check_passed: true
  };
}

let title = parsed.title || inputItem.raw_title || 'Minecraft Mod';
let description = parsed.description || '';

const titleLower = title.toLowerCase();
const descLower = description.toLowerCase();

let hasBrand = false;
for (const brand of BANNED_BRANDS) {
  if (titleLower.includes(brand) || descLower.includes(brand)) {
    hasBrand = true;
    const regex = new RegExp(brand, 'gi');
    title = title.replace(regex, 'Premium');
    description = description.replace(regex, 'premium quality');
  }
}

title = title.replace(/[^a-zA-Z0-9\s-]/g, '').trim();
if (title.length < 4) title = title + ' Mod';
if (title.length > 30) title = title.substring(0, 27) + '...';

if (description.length < 50) {
  description = `${description} Enhances your Minecraft experience with new features and content.`;
}
if (description.length > 3000) {
  description = description.substring(0, 2997) + '...';
}

return [{
  json: {
    id: inputItem.id,
    section: inputItem.section,
    category: inputItem.category || 'general',
    image: inputItem.image_filename,
    file: inputItem.mod_filename || '',
    title: title,
    description: description,
    source_url: inputItem.page_url,
    qa_score: inputItem.qa_score,
    was_regenerated: inputItem.was_regenerated || false,
    brand_cleaned: hasBrand
  },
  binary: inputBinary
}];

