const update = $json;
const text = update.message?.text || '';
const parts = text.trim().split(/\s+/);
const command = parts[0] || '';

let mode = 'new';
let game = 'Minecraft';
let template = 'Crafty';
let targetCount = 50;
let existingFileUrl = null;
let marketingCount = 5;

if (command === '/update') {
  mode = 'update';
  existingFileUrl = parts[1] || null;
  targetCount = parts[2] ? Number(parts[2]) : 100;
  marketingCount = parts[3] ? Number(parts[3]) : 5;
} else if (command === '/new_project') {
  const args = parts.slice(1);
  game = args[0] || 'Minecraft';
  template = args[1] || 'Crafty';
  targetCount = args[3] ? Number(args[3]) : 50;
} else if (text.includes('Сегмент:') || text.includes('Minecraft')) {
  game = 'Minecraft';
  template = 'Crafty';
}

return [{
  json: {
    chat_id: update.message.chat.id,
    message_id: update.message.message_id,
    raw_text: text,
    command,
    mode,
    game,
    template,
