// Динамический поиск fileUrl в ответе Manus
const manusResponse = $json;

let fileUrl = null;

// Ищем fileUrl в массиве output
if (manusResponse.output && Array.isArray(manusResponse.output)) {
  for (const outputItem of manusResponse.output) {
    if (outputItem.content && Array.isArray(outputItem.content)) {
      for (const contentItem of outputItem.content) {
        // Ищем тип output_file с fileUrl
        if (contentItem.type === 'output_file' && contentItem.fileUrl) {
          fileUrl = contentItem.fileUrl;
          break;
        }
      }
    }
    if (fileUrl) break;
  }
}

// Fallback: ищем любой fileUrl в структуре
if (!fileUrl) {
  const jsonStr = JSON.stringify(manusResponse);
  const match = jsonStr.match(/"fileUrl"\s*:\s*"([^"]+)"/);
  if (match) {
    fileUrl = match[1];
  }
}

if (!fileUrl) {
  throw new Error('fileUrl not found in Manus response');
}

return [{
  json: {
    file_url: fileUrl,
    file_name: 'mods_output.json'
  }
}];
